var e=`1`,t=`1.0.0`,n=`2026-05-03`,r=[{id:`incoterm`,label:`Incoterms`},{id:`trade_instrument`,label:`Trade Finance`},{id:`regulation`,label:`Regulatory`},{id:`logistics`,label:`Logistics`},{id:`commodity_class`,label:`Commodity Class`},{id:`chokepoint`,label:`Chokepoints`},{id:`market_structure`,label:`Market Structure`}],i=[{id:`incoterm_exw`,term:`EXW (Ex Works)`,category:`incoterm`,shortDef:`Buyer collects at seller's premises; buyer bears all risk and cost.`,definition:`Ex Works is the Incoterm placing maximum responsibility on the buyer. The seller's only obligation is to make goods available at their named premises. The buyer arranges export clearance, transport, insurance, and import — and bears risk from the moment goods are placed at their disposal.`,applicableStages:[`origin`],riskClass:`high`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_fca`,`incoterm_ddp`,`instrument_open_account`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`until goods are made available at the named place`,buyerOwnsRiskFrom:`the moment of placement at seller's premises`}},{id:`incoterm_fca`,term:`FCA (Free Carrier)`,category:`incoterm`,shortDef:`Seller delivers cleared goods to buyer's named carrier.`,definition:`Free Carrier requires the seller to deliver goods, cleared for export, to a carrier nominated by the buyer at a named place. Risk transfers when goods are loaded onto the buyer's collecting vehicle (or made available at named terminal). The most flexible Incoterm, suitable for any mode.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_exw`,`incoterm_fob`,`incoterm_cpt`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[`chain_lithium_ev`],incotermsRiskBoundary:{sellerOwnsRiskThrough:`delivery of export-cleared goods to buyer's carrier`,buyerOwnsRiskFrom:`loading onto buyer's collecting vehicle at named place`}},{id:`incoterm_fob`,term:`FOB (Free on Board)`,category:`incoterm`,shortDef:`Seller delivers on board the vessel at port of shipment.`,definition:`Free on Board applies only to sea/inland waterway transport. The seller bears risk and cost until goods are loaded on board the vessel at the named port. Buyer arranges and pays main carriage and insurance from that point. Common for bulk and break-bulk commodities.`,applicableStages:[`origin`,`transit`],riskClass:`medium`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_fca`,`incoterm_cif`,`incoterm_cfr`],relatedCommodityIds:[`uranium`,`lng`,`iron_ore`],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`loading on board vessel at named port of shipment`,buyerOwnsRiskFrom:`the moment goods cross the ship's rail`}},{id:`incoterm_cif`,term:`CIF (Cost, Insurance, Freight)`,category:`incoterm`,shortDef:`Seller pays freight and insurance to destination port; risk transfers at origin.`,definition:`Cost, Insurance and Freight obliges the seller to contract and pay for carriage and minimum-cover insurance to the named destination port. Risk transfers to the buyer when goods are on board the vessel at origin — a key gotcha for buyers who think they're protected.`,applicableStages:[`origin`,`transit`],riskClass:`medium`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_fob`,`incoterm_cfr`,`incoterm_cip`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`loading on board vessel at origin (despite paying freight to destination)`,buyerOwnsRiskFrom:`loading on board vessel at origin`}},{id:`incoterm_cfr`,term:`CFR (Cost and Freight)`,category:`incoterm`,shortDef:`Seller pays freight to destination; insurance is buyer's responsibility.`,definition:`Cost and Freight is identical to CIF but without the insurance obligation. Sea/waterway only. Buyer must arrange their own cargo insurance even though the seller pays freight to destination.`,applicableStages:[`origin`,`transit`],riskClass:`medium`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_cif`,`incoterm_fob`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`loading on board vessel at origin (freight paid through to destination)`,buyerOwnsRiskFrom:`loading on board vessel at origin`}},{id:`incoterm_cpt`,term:`CPT (Carriage Paid To)`,category:`incoterm`,shortDef:`Seller pays carriage to named destination, any mode; risk transfers at first carrier.`,definition:`Carriage Paid To is the multimodal equivalent of CFR. Seller arranges and pays main carriage to a named destination but risk transfers when goods are handed to the first carrier. Common for containerized shipments.`,applicableStages:[`origin`,`transit`],riskClass:`medium`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_cip`,`incoterm_cfr`,`incoterm_fca`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`handing goods to the first carrier`,buyerOwnsRiskFrom:`first-carrier handover at origin`}},{id:`incoterm_cip`,term:`CIP (Carriage and Insurance Paid To)`,category:`incoterm`,shortDef:`Seller pays carriage and all-risk insurance; risk transfers at first carrier.`,definition:`Carriage and Insurance Paid To matches CPT plus a seller obligation to obtain ICC Clauses (A) all-risk insurance. Updated in Incoterms 2020 from minimum cover to maximum cover.`,applicableStages:[`origin`,`transit`],riskClass:`low`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_cpt`,`incoterm_cif`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`handing goods to first carrier; insurance covers main carriage`,buyerOwnsRiskFrom:`first-carrier handover (with insurance protection in place)`}},{id:`incoterm_dap`,term:`DAP (Delivered at Place)`,category:`incoterm`,shortDef:`Seller delivers ready for unloading at named destination; buyer clears import.`,definition:`Delivered at Place: seller bears all risk and cost until goods arrive at the named destination ready for unloading. Buyer is responsible for unloading and import formalities/duties.`,applicableStages:[`destination`],riskClass:`low`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_dpu`,`incoterm_ddp`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`arrival at named destination ready for unloading`,buyerOwnsRiskFrom:`unloading at destination plus import clearance`}},{id:`incoterm_dpu`,term:`DPU (Delivered at Place Unloaded)`,category:`incoterm`,shortDef:`Seller delivers and unloads at destination; buyer handles import.`,definition:`Delivered at Place Unloaded (new in Incoterms 2020, replaces DAT): seller bears risk and cost through unloading at the named destination. Buyer handles import customs and duties only.`,applicableStages:[`destination`],riskClass:`low`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_dap`,`incoterm_ddp`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[],incotermsRiskBoundary:{sellerOwnsRiskThrough:`delivery and unloading at named destination`,buyerOwnsRiskFrom:`import clearance at destination`}},{id:`incoterm_ddp`,term:`DDP (Delivered Duty Paid)`,category:`incoterm`,shortDef:`Seller bears all risk, cost, and import duties through to destination.`,definition:`Delivered Duty Paid puts maximum obligation on the seller: risk, cost, transport, import clearance, and duties through to the named destination. Used when the buyer cannot or will not act as importer of record. Highest seller exposure.`,applicableStages:[`origin`,`transit`,`destination`],riskClass:`critical`,regulatoryBody:`ICC`,relatedTermIds:[`incoterm_dap`,`incoterm_dpu`],relatedCommodityIds:[`uranium`,`pharma_api`],relatedChokepoints:[`chokepoint_suez`,`chokepoint_bosphorus`],exampleChainIds:[`chain_nuclear_fuel_kaz_se`],incotermsRiskBoundary:{sellerOwnsRiskThrough:`the entire chain — origin, all transit corridors, destination clearance and delivery`,buyerOwnsRiskFrom:`receipt at named destination only`}},{id:`instrument_lc`,term:`Letter of Credit (L/C)`,category:`trade_instrument`,shortDef:`Bank guarantee that seller is paid when documents conform to terms.`,definition:`An irrevocable Letter of Credit (UCP 600) is a written undertaking by a bank to pay the seller upon presentation of conforming documents. Variants: confirmed L/C (a second bank adds its undertaking), revolving, transferable. Standard for high-value cross-border trade where parties don't know each other.`,applicableStages:[`origin`,`transit`],riskClass:`low`,regulatoryBody:`ICC UCP 600`,relatedTermIds:[`instrument_standby_lc`,`instrument_doc_collection`,`instrument_bank_guarantee`],relatedCommodityIds:[`cobalt`,`lng`,`uranium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`instrument_standby_lc`,term:`Standby Letter of Credit (SBLC)`,category:`trade_instrument`,shortDef:`Bank undertaking drawn only on default; functions as a guarantee.`,definition:`A Standby L/C is payable only if the buyer fails to perform. Governed by ISP98 or UCP 600. Frequently used as a performance guarantee in long-term offtake contracts and for advance-payment protection.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:`ICC ISP98`,relatedTermIds:[`instrument_lc`,`instrument_bank_guarantee`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`instrument_doc_collection`,term:`Documentary Collection (D/P, D/A)`,category:`trade_instrument`,shortDef:`Bank handles document exchange but does not guarantee payment.`,definition:`Documents Against Payment (D/P) — buyer gets shipping documents only on payment. Documents Against Acceptance (D/A) — buyer gets documents on accepting a time draft. Cheaper than L/C but no payment guarantee. Governed by URC 522.`,applicableStages:[`origin`,`transit`],riskClass:`medium`,regulatoryBody:`ICC URC 522`,relatedTermIds:[`instrument_lc`,`instrument_open_account`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`instrument_open_account`,term:`Open Account`,category:`trade_instrument`,shortDef:`Goods shipped, payment due 30/60/90 days later; maximum buyer leverage.`,definition:`Open account terms ship goods on credit with payment due at a future date. Common in mature trading relationships and intra-EU trade where commercial trust is established. Carries highest seller credit risk; often hedged via factoring or trade credit insurance.`,applicableStages:[`origin`],riskClass:`high`,regulatoryBody:null,relatedTermIds:[`instrument_factoring`,`instrument_doc_collection`],relatedCommodityIds:[`pharma_api`],relatedChokepoints:[],exampleChainIds:[]},{id:`instrument_bank_guarantee`,term:`Bank Guarantee`,category:`trade_instrument`,shortDef:`Bank promises to pay on demand if a contract obligation is not performed.`,definition:`An on-demand bank guarantee (URDG 758) provides irrevocable payment to the beneficiary on first written demand. Common forms: bid bond, performance bond, advance payment guarantee, retention guarantee. Used heavily in EPC and infrastructure procurement.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:`ICC URDG 758`,relatedTermIds:[`instrument_standby_lc`,`instrument_lc`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`instrument_factoring`,term:`Factoring`,category:`trade_instrument`,shortDef:`Sell receivables at a discount to a factor for immediate cash.`,definition:`The seller sells trade receivables to a factor at a discount, receiving immediate cash flow. Recourse factoring leaves credit risk with the seller; non-recourse factoring transfers it to the factor. Common in commoditized B2B trade.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`instrument_forfaiting`,`instrument_open_account`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`instrument_forfaiting`,term:`Forfaiting`,category:`trade_instrument`,shortDef:`Non-recourse purchase of medium-term export receivables.`,definition:`Forfaiting is the non-recourse discounting of medium- to long-term export receivables (typically 6 months to 7 years) backed by a bank-avalised promissory note or accepted bill of exchange. Used for capital goods and infrastructure exports.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:`ICC URF 800`,relatedTermIds:[`instrument_factoring`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`regulation_itar`,term:`ITAR (International Traffic in Arms Regulations)`,category:`regulation`,shortDef:`US export controls on defense articles and services.`,definition:`ITAR (22 CFR 120-130) controls the export and import of defense articles and services on the US Munitions List (USML). Administered by the US State Department's DDTC. Covers beryllium, hafnium, certain enrichment equipment, encryption technology, and related technical data. Violations carry criminal liability.`,applicableStages:[`origin`,`destination`],riskClass:`critical`,regulatoryBody:`US State Dept DDTC`,relatedTermIds:[`regulation_ear`,`regulation_ofac`],relatedCommodityIds:[`uranium`,`beryllium`,`hafnium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`regulation_ear`,term:`EAR (Export Administration Regulations)`,category:`regulation`,shortDef:`US dual-use export controls; covers semiconductors, software, sensors.`,definition:`EAR (15 CFR 730-774) administered by US Commerce BIS controls dual-use items on the Commerce Control List (CCL). Includes Foreign-Direct Product Rule extensions. Critical for advanced-node semiconductors (<14nm), AI chips, and quantum technology. Entity List restrictions add further compliance burden.`,applicableStages:[`origin`,`destination`],riskClass:`critical`,regulatoryBody:`US Commerce BIS`,relatedTermIds:[`regulation_itar`,`regulation_ofac`,`regulation_chips_act`],relatedCommodityIds:[`semiconductor`,`rare_earth`],relatedChokepoints:[`chokepoint_taiwan_strait`],exampleChainIds:[]},{id:`regulation_ofac`,term:`OFAC Sanctions`,category:`regulation`,shortDef:`US Treasury sanctions including SDN list and sectoral programs.`,definition:`Office of Foreign Assets Control administers and enforces US economic and trade sanctions. Specially Designated Nationals (SDN) list freezes assets and prohibits transactions. Secondary sanctions reach non-US persons. Sectoral sanctions target Russian energy, financial, and defense industries.`,applicableStages:[`origin`,`transit`,`destination`],riskClass:`critical`,regulatoryBody:`US Treasury OFAC`,relatedTermIds:[`regulation_itar`,`regulation_ear`],relatedCommodityIds:[`lng`,`oil`,`uranium`],relatedChokepoints:[`chokepoint_hormuz`,`chokepoint_bosphorus`],exampleChainIds:[]},{id:`regulation_eu_reach`,term:`EU REACH`,category:`regulation`,shortDef:`EU chemical registration; threshold 1 t/year per importer.`,definition:`Registration, Evaluation, Authorisation and Restriction of Chemicals — EU regulation requiring importers and manufacturers of chemical substances >1 t/year to register with ECHA. Article 33 imposes Substance of Very High Concern (SVHC) communication duties throughout the supply chain.`,applicableStages:[`destination`],riskClass:`high`,regulatoryBody:`EU ECHA`,relatedTermIds:[`regulation_eu_cbam`],relatedCommodityIds:[`pharma_api`,`rare_earth`],relatedChokepoints:[],exampleChainIds:[]},{id:`regulation_iaea_safeguards`,term:`IAEA Safeguards`,category:`regulation`,shortDef:`International nuclear material accountancy and inspections.`,definition:`International Atomic Energy Agency safeguards (INFCIRC/153, INFCIRC/540 Additional Protocol) verify that nuclear material is not diverted from peaceful uses. Apply to all transfers of source material (uranium, thorium) and special fissionable material. Non-compliance can trigger UN Security Council referral.`,applicableStages:[`origin`,`transit`,`destination`],riskClass:`critical`,regulatoryBody:`IAEA`,relatedTermIds:[`regulation_itar`,`regulation_nsg`],relatedCommodityIds:[`uranium`,`enriched_uranium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`regulation_nsg`,term:`Nuclear Suppliers Group (NSG)`,category:`regulation`,shortDef:`48-state regime restricting nuclear and nuclear-related dual-use exports.`,definition:`The NSG controls trade in nuclear material, equipment, and dual-use technology. Two control lists: Trigger List (INFCIRC/254 Part 1) and Dual-Use List (Part 2). Member states require government authorization for any listed export and apply non-proliferation conditions.`,applicableStages:[`origin`,`destination`],riskClass:`critical`,regulatoryBody:`NSG`,relatedTermIds:[`regulation_iaea_safeguards`,`regulation_itar`],relatedCommodityIds:[`uranium`,`enriched_uranium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`regulation_basel`,term:`Basel Convention`,category:`regulation`,shortDef:`International control of transboundary movement of hazardous waste.`,definition:`Multilateral treaty requiring prior informed consent for transboundary shipments of hazardous and other wastes. The Basel Ban Amendment (2019) prohibits OECD-to-non-OECD hazardous waste exports. Critical for battery recycling, e-waste, and certain pharma intermediates.`,applicableStages:[`origin`,`transit`,`destination`],riskClass:`high`,regulatoryBody:`UN Basel`,relatedTermIds:[`regulation_eu_reach`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`regulation_cites`,term:`CITES`,category:`regulation`,shortDef:`International trade controls for endangered species and bio-derived materials.`,definition:`Convention on International Trade in Endangered Species. Three appendices grading risk; Appendix I bans most commercial trade. Affects bio-pharma intermediates derived from listed species and luxury goods (timber, exotic leather).`,applicableStages:[`origin`,`destination`],riskClass:`high`,regulatoryBody:`UN CITES Secretariat`,relatedTermIds:[],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`regulation_eu_cbam`,term:`EU CBAM (Carbon Border Adjustment)`,category:`regulation`,shortDef:`EU carbon import tariff phasing in from 2026 on cement, steel, aluminium, fertilizer, electricity, hydrogen.`,definition:`Carbon Border Adjustment Mechanism imposes a price on embedded emissions of imports equivalent to EU ETS. Transitional reporting since Oct 2023; financial liability from Jan 2026. Materially shifts steel, aluminium, and fertilizer landed costs. Sector expansions expected.`,applicableStages:[`destination`],riskClass:`high`,regulatoryBody:`EU Commission`,relatedTermIds:[`regulation_eu_reach`],relatedCommodityIds:[`steel`,`aluminium`,`iron_ore`],relatedChokepoints:[],exampleChainIds:[]},{id:`regulation_chips_act`,term:`US CHIPS Act`,category:`regulation`,shortDef:`US semiconductor industrial policy + entity list extensions.`,definition:`CHIPS and Science Act of 2022: $52B in subsidies for US semiconductor manufacturing plus entity-list and FDPR rules restricting advanced-node (<14nm logic, 18nm DRAM, 128-layer NAND) tools and outputs to China-based facilities. Recipients face 10-year guardrails on Chinese expansion.`,applicableStages:[`origin`,`destination`],riskClass:`critical`,regulatoryBody:`US Commerce`,relatedTermIds:[`regulation_ear`],relatedCommodityIds:[`semiconductor`],relatedChokepoints:[`chokepoint_taiwan_strait`],exampleChainIds:[]},{id:`logistics_demurrage`,term:`Demurrage`,category:`logistics`,shortDef:`Charge for holding a container at port beyond agreed free time.`,definition:`Daily charge levied by the carrier when the consignee fails to clear a container from the terminal within the contracted free-time window. Distinct from detention (charged when container is held outside terminal). Rates accelerate after second tier.`,applicableStages:[`destination`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`logistics_detention`,`logistics_free_time`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_detention`,term:`Detention`,category:`logistics`,shortDef:`Charge for holding a carrier's container outside the terminal beyond free time.`,definition:`Per-day charge applied when an importer keeps a carrier-owned container past the contractual free-time after pickup. Both demurrage and detention surged 4-6x during 2021–22 supply crisis; FMC 'Final Rule' (2024) imposed disclosure standards for US container shipments.`,applicableStages:[`destination`],riskClass:`medium`,regulatoryBody:`US FMC`,relatedTermIds:[`logistics_demurrage`,`logistics_free_time`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_free_time`,term:`Free Time`,category:`logistics`,shortDef:`Contractually allowed period for terminal storage / container use before charges accrue.`,definition:`Number of free days included in a freight tariff or contract before demurrage (terminal) or detention (container) begins. Typically 4–7 days at origin and destination but compressed during congestion.`,applicableStages:[`origin`,`destination`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`logistics_demurrage`,`logistics_detention`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_dead_freight`,term:`Dead Freight`,category:`logistics`,shortDef:`Charge billed for booked but un-shipped cargo space.`,definition:`Compensation owed to a carrier for vessel space booked but not utilised by the charterer. Functions as liquidated damages for under-shipment under voyage charters and contracts of affreightment.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`logistics_take_or_pay`],relatedCommodityIds:[`lng`,`iron_ore`],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_transhipment`,term:`Transhipment`,category:`logistics`,shortDef:`Mid-route transfer between vessels or modes at an intermediate hub.`,definition:`Movement of cargo from one carrier or vessel to another at an intermediate point en route. Common at hub ports (Singapore, Rotterdam, Algeciras). Adds dwell, handling cost, and damage risk; often unavoidable on niche origin–destination pairs.`,applicableStages:[`transit`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`logistics_feeder_service`,`logistics_break_bulk`],relatedCommodityIds:[],relatedChokepoints:[`chokepoint_malacca`],exampleChainIds:[]},{id:`logistics_feeder_service`,term:`Feeder Service`,category:`logistics`,shortDef:`Short-sea vessel that connects secondary ports to deep-sea hubs.`,definition:`A coastal or short-sea vessel collecting and distributing containers between regional ports and a transhipment hub served by larger ocean carriers. Adds 1–4 days to mainline schedules.`,applicableStages:[`transit`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`logistics_transhipment`,`logistics_nvocc`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_break_bulk`,term:`Break-Bulk`,category:`logistics`,shortDef:`Non-containerised cargo shipped as individually handled units.`,definition:`Cargo loaded individually rather than in containers — bagged commodities, drums, machinery, project cargo. Higher handling cost and damage risk than containerised; used for oversized or specialised shipments.`,applicableStages:[`transit`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`logistics_roro`,`logistics_transhipment`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_roro`,term:`RoRo (Roll-on/Roll-off)`,category:`logistics`,shortDef:`Vessels carrying wheeled cargo driven on/off via internal ramps.`,definition:`Vessels (typically PCTC — Pure Car & Truck Carriers — or ConRo hybrids) where wheeled cargo is rolled directly aboard. Standard for vehicles, trailers, heavy equipment. Major ports: Bremerhaven, Zeebrugge, Baltimore, Yokohama.`,applicableStages:[`transit`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`logistics_break_bulk`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_nvocc`,term:`NVOCC (Non-Vessel Operating Common Carrier)`,category:`logistics`,shortDef:`Carrier that issues bills of lading without operating its own ships.`,definition:`An NVOCC sells ocean freight services under its own house bill of lading while purchasing space from vessel operators. Acts as a consolidator. Must be licensed by the FMC for US trades.`,applicableStages:[`origin`,`transit`],riskClass:`low`,regulatoryBody:`US FMC`,relatedTermIds:[`logistics_mto`,`logistics_feeder_service`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_mto`,term:`MTO (Multimodal Transport Operator)`,category:`logistics`,shortDef:`Single contract carrier responsible end-to-end across multiple transport modes.`,definition:`An MTO concludes a multimodal transport contract assuming responsibility for the whole journey across two or more modes (e.g., rail+sea+truck) under a single combined transport bill of lading (FBL or equivalent).`,applicableStages:[`origin`,`transit`,`destination`],riskClass:`low`,regulatoryBody:`UN MT Convention`,relatedTermIds:[`logistics_nvocc`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_bol`,term:`Bill of Lading (B/L)`,category:`logistics`,shortDef:`Document of title; contract of carriage; receipt for goods.`,definition:`Three legal functions in one document: receipt of goods, evidence of contract of carriage, and document of title. Variants — Order B/L (negotiable), Straight B/L (non-negotiable), Sea Waybill (no title transfer), Express Release, Switch B/L.`,applicableStages:[`origin`,`destination`],riskClass:`medium`,regulatoryBody:`Hague-Visby / Rotterdam Rules`,relatedTermIds:[`instrument_lc`,`logistics_seaway_bill`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_seaway_bill`,term:`Sea Waybill`,category:`logistics`,shortDef:`Non-negotiable carriage receipt; faster delivery, no title transfer.`,definition:`Functions as receipt and evidence of contract but is not a document of title. Cargo is released to the named consignee on identification — eliminates the need for original B/L surrender. Common in intra-group, open-account, or trusted-counterparty trade.`,applicableStages:[`origin`,`destination`],riskClass:`low`,regulatoryBody:`CMI Uniform Rules for Sea Waybills`,relatedTermIds:[`logistics_bol`,`instrument_open_account`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`logistics_take_or_pay`,term:`Take-or-Pay`,category:`logistics`,shortDef:`Buyer must pay contracted volume even if not lifted.`,definition:`Long-term offtake clause obliging the buyer to either take a minimum contracted volume or pay for it as if taken. Underpins financing of capital-intensive projects (LNG, mining, pipelines) by guaranteeing producer revenue.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`market_offtake_agreement`,`logistics_dead_freight`],relatedCommodityIds:[`lng`,`uranium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`logistics_hell_or_high_water`,term:`Hell-or-High-Water Clause`,category:`logistics`,shortDef:`Payment obligation continues regardless of any event short of impossibility.`,definition:`Absolute payment undertaking surviving force majeure, performance failure, or change in law. Common in equipment lease and vessel charter financing where lender requires unconditional payment to support debt service.`,applicableStages:[`origin`],riskClass:`high`,regulatoryBody:null,relatedTermIds:[`logistics_take_or_pay`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_suez`,term:`Suez Canal`,category:`chokepoint`,shortDef:`193 km Egyptian canal carrying ~12% of global trade.`,definition:`The Suez Canal handles roughly 12% of global trade and ~30% of container volume between Asia and Europe. The 2021 Ever Given grounding and the post-2023 Red Sea crisis demonstrated systemic re-route risk; Cape of Good Hope diversion adds 10–14 days and ~$15k/TEU.`,applicableStages:[`transit`],riskClass:`critical`,regulatoryBody:`Suez Canal Authority`,relatedTermIds:[`chokepoint_cape_good_hope`,`chokepoint_bosphorus`],relatedCommodityIds:[`lng`,`oil`,`uranium`],relatedChokepoints:[`chokepoint_cape_good_hope`],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`chokepoint_hormuz`,term:`Strait of Hormuz`,category:`chokepoint`,shortDef:`39 km strait carrying ~20% of global oil and ~25% of LNG.`,definition:`Connects the Persian Gulf to the Gulf of Oman. ~21 million barrels of oil and ~25% of seaborne LNG transit daily. Iranian interdiction risk drives persistent geopolitical premium in energy markets. No commercially viable bypass for Gulf hydrocarbons exists.`,applicableStages:[`transit`],riskClass:`critical`,regulatoryBody:null,relatedTermIds:[`regulation_ofac`,`chokepoint_suez`],relatedCommodityIds:[`lng`,`oil`],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_malacca`,term:`Strait of Malacca`,category:`chokepoint`,shortDef:`World's busiest shipping lane: ~25% of global trade, ~80% of China's oil imports.`,definition:`Narrow 805 km waterway between Malaysia and Sumatra connecting the Indian and Pacific Oceans. Singapore is the principal transhipment hub. Persistent piracy, congestion at Singapore terminals, and military-tension exposure drive contingency planning around the Lombok and Sunda Straits.`,applicableStages:[`transit`],riskClass:`high`,regulatoryBody:null,relatedTermIds:[`logistics_transhipment`],relatedCommodityIds:[`oil`,`semiconductor`,`pharma_api`],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_panama`,term:`Panama Canal`,category:`chokepoint`,shortDef:`82 km lock canal between Atlantic and Pacific; ~5% of world maritime trade.`,definition:`Critical for US East Coast — Asia trade and US LNG export economics. The 2023–24 drought reduced daily Neopanamax transits by ~35%, forcing auctions for slot priority and re-routing via Suez or Cape Horn. Permanent water-supply uncertainty under climate change.`,applicableStages:[`transit`],riskClass:`high`,regulatoryBody:`Panama Canal Authority`,relatedTermIds:[`chokepoint_cape_horn`],relatedCommodityIds:[`lng`],relatedChokepoints:[`chokepoint_cape_horn`],exampleChainIds:[]},{id:`chokepoint_cape_horn`,term:`Cape Horn`,category:`chokepoint`,shortDef:`Southernmost tip of South America; backup when Panama Canal is restricted.`,definition:`Used as Panama Canal bypass during low-water events. Adds 8–10 days to a typical Asia–US East Coast voyage and exposes vessels to severe Southern Ocean weather. Insurance premia spike when used; rarely the planned route.`,applicableStages:[`transit`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`chokepoint_panama`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_cape_good_hope`,term:`Cape of Good Hope`,category:`chokepoint`,shortDef:`Primary Suez bypass for Asia–Europe trade since 2024 Red Sea crisis.`,definition:`Rounding Africa's southern tip adds ~3,500 nautical miles vs. Suez. Traffic up roughly 80% post-2023; secondary congestion has emerged at Durban and Cape Town. Primary bypass for tankers, bulkers, and box ships avoiding Houthi attack risk.`,applicableStages:[`transit`],riskClass:`high`,regulatoryBody:null,relatedTermIds:[`chokepoint_suez`],relatedCommodityIds:[`lng`,`oil`],relatedChokepoints:[`chokepoint_suez`],exampleChainIds:[]},{id:`chokepoint_bosphorus`,term:`Bosphorus Strait`,category:`chokepoint`,shortDef:`30 km Turkish strait controlling Black Sea ↔ Mediterranean traffic.`,definition:`Governed by the 1936 Montreux Convention; Turkey controls passage. Russia–Ukraine war has dramatically reshaped Black Sea grain and oil flows; tanker insurance for Black Sea transits sits at multi-decade highs. Dual narrow segments make Bosphorus highly accident-prone.`,applicableStages:[`transit`],riskClass:`high`,regulatoryBody:`Montreux Convention 1936`,relatedTermIds:[`regulation_ofac`,`chokepoint_suez`],relatedCommodityIds:[`oil`,`uranium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`]},{id:`chokepoint_taiwan_strait`,term:`Taiwan Strait`,category:`chokepoint`,shortDef:`180 km strait carrying ~50% of global container traffic; semiconductor lifeline.`,definition:`Taiwan produces roughly 90% of advanced (<7 nm) semiconductors. Periodic PLA exercises demonstrate the speed at which freight rates and risk premia react. Air re-routing alternatives exist for chips but at $4–8k/kg premium; sea bypass via Bashi Channel adds 1–2 days.`,applicableStages:[`transit`],riskClass:`critical`,regulatoryBody:null,relatedTermIds:[`regulation_chips_act`,`regulation_ear`],relatedCommodityIds:[`semiconductor`],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_giuk_gap`,term:`GIUK Gap`,category:`chokepoint`,shortDef:`Greenland–Iceland–UK naval chokepoint; NATO Atlantic monitoring zone.`,definition:`The maritime gap between Greenland, Iceland, and the United Kingdom. Cold-War-era ASW chokepoint regaining prominence with renewed Russian submarine activity. Cable-cutting and undersea infrastructure risk in this corridor has heightened insurance scrutiny on transatlantic data and energy cables.`,applicableStages:[`transit`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`chokepoint_danish_straits`,term:`Danish Straits`,category:`chokepoint`,shortDef:`Skagerrak/Kattegat passage; Russian Baltic crude export route.`,definition:`The Great Belt, Little Belt, and Øresund collectively control Baltic Sea access. Carry the bulk of Russian crude exports out of Primorsk and Ust-Luga. Sanctions enforcement and shadow-fleet identification has intensified Danish authority surveillance here.`,applicableStages:[`transit`],riskClass:`high`,regulatoryBody:`Copenhagen Treaty 1857`,relatedTermIds:[`regulation_ofac`],relatedCommodityIds:[`oil`],relatedChokepoints:[],exampleChainIds:[]},{id:`market_spot`,term:`Spot Price`,category:`market_structure`,shortDef:`Current market price for immediate delivery.`,definition:`Price for purchase and physical delivery now (typically T+2 settlement). Aggregated by Price Reporting Agencies (Platts, Argus, ICIS) into daily benchmark assessments used in formula contracts.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`market_forward`,`market_benchmark`,`market_pra`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`market_forward`,term:`Forward Contract`,category:`market_structure`,shortDef:`Bilateral contract to deliver/take a commodity at a future date and price.`,definition:`Customisable OTC agreement, no daily mark-to-market. Standard in physical energy and metals trading. Distinguished from futures (exchange-traded, standardised, margined) and from a swap (cash-settled).`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`market_futures`,`market_spot`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`market_futures`,term:`Futures Contract`,category:`market_structure`,shortDef:`Standardised exchange-traded contract for future delivery, daily margin.`,definition:`Standardised contract traded on a regulated exchange (CME, ICE, LME, SHFE) with central clearing and daily variation margin. Removes counterparty credit risk; supports liquid hedging and price discovery.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:`CFTC / FCA / etc.`,relatedTermIds:[`market_forward`,`market_contango`,`market_backwardation`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`market_contango`,term:`Contango`,category:`market_structure`,shortDef:`Forward price > spot — typical for storable commodities with carrying cost.`,definition:`Term structure where forward prices exceed spot, reflecting storage, financing, and insurance costs. Incentivises floating-storage and 'cash-and-carry' arbitrage. Persistently steep contango can flip the physical market into oversupply.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`market_backwardation`,`market_futures`],relatedCommodityIds:[`oil`,`lng`],relatedChokepoints:[],exampleChainIds:[]},{id:`market_backwardation`,term:`Backwardation`,category:`market_structure`,shortDef:`Spot price > forward — signals current scarcity and tight market.`,definition:`Inverted term structure where spot prices exceed forwards. Indicates physical tightness or convenience yield from holding inventory. Producer hedging programmes and storage economics deteriorate; consumer hedgers face roll losses.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`market_contango`,`market_futures`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`market_pra`,term:`Price Reporting Agency (PRA)`,category:`market_structure`,shortDef:`Independent assessor publishing daily reference prices (Platts, Argus, ICIS).`,definition:`PRAs collect bids, offers, and trades from market participants and publish daily price assessments used by physical and derivatives contracts. IOSCO Principles for Oil PRAs (2012) set methodology, governance, and conflicts standards.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:`IOSCO`,relatedTermIds:[`market_spot`,`market_benchmark`],relatedCommodityIds:[],relatedChokepoints:[],exampleChainIds:[]},{id:`market_benchmark`,term:`Benchmark`,category:`market_structure`,shortDef:`Reference price used as basis for physical and derivatives contracts (Brent, WTI, LME copper).`,definition:`A widely accepted reference price used as the pricing basis for physical contracts and derivatives. Brent (dated, futures) and WTI for crude; LME 3-month for industrial metals; TTF for European gas; JKM for Asian LNG; Platts CFR China 62% Fe for iron ore.`,applicableStages:[`origin`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`market_pra`,`market_spot`],relatedCommodityIds:[`oil`,`lng`,`iron_ore`],relatedChokepoints:[],exampleChainIds:[]},{id:`market_offtake_agreement`,term:`Offtake Agreement`,category:`market_structure`,shortDef:`Long-term contract committing buyer to purchase project output.`,definition:`Long-term sales agreement between a producer and a buyer, often signed before construction to support project finance. Common in mining, LNG, and renewable power (PPA variant). Pricing may be fixed, formula-linked, or hybrid.`,applicableStages:[`origin`],riskClass:`medium`,regulatoryBody:null,relatedTermIds:[`logistics_take_or_pay`,`market_throughput_agreement`],relatedCommodityIds:[`lng`,`uranium`,`lithium`],relatedChokepoints:[],exampleChainIds:[`chain_nuclear_fuel_kaz_se`,`chain_lithium_ev`]},{id:`market_throughput_agreement`,term:`Throughput Agreement`,category:`market_structure`,shortDef:`Shipper commits to send minimum volume through a pipeline/terminal.`,definition:`Contract obligating a shipper to push at least a stated volume through a pipeline or terminal in a given period (or pay as if shipped). Bankable cash flow that supports infrastructure project finance.`,applicableStages:[`transit`],riskClass:`low`,regulatoryBody:null,relatedTermIds:[`logistics_take_or_pay`,`market_offtake_agreement`],relatedCommodityIds:[`oil`,`lng`],relatedChokepoints:[],exampleChainIds:[]}],a={schemaVersion:`1`,version:t,generatedAt:n,categories:r,terms:i};export{r as categories,a as default,n as generatedAt,e as schemaVersion,i as terms,t as version};
